(window.webpackJsonp=window.webpackJsonp||[]).push([[961],{907:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">source</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">target</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">allowedSwaps</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minimumHammingDistance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">source, target, allowedSwaps</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> len=source.length\\n    <span class=\\"hljs-keyword\\">let</span> uf=<span class=\\"hljs-built_in\\">Array</span>(len).fill().map(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">_,i</span>)=&gt;</span>i)\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">union</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n        <span class=\\"hljs-keyword\\">let</span> i=find(a)\\n        <span class=\\"hljs-keyword\\">let</span> j=find(b)\\n        <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">return</span>\\n        uf[i]=j\\n    }\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">find</span>(<span class=\\"hljs-params\\">i</span>)</span>{\\n        <span class=\\"hljs-keyword\\">if</span>(uf[i]!==i){\\n            uf[i]=find(uf[i])\\n        }\\n        <span class=\\"hljs-keyword\\">return</span> uf[i]\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [x,y] <span class=\\"hljs-keyword\\">of</span> allowedSwaps){\\n        union(x,y)\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> util=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;uf.length;i++){\\n        uf[i]=find(uf[i])\\n        util.push([uf[i],i])\\n    }\\n    util.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>[a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>]])\\n    <span class=\\"hljs-comment\\">// console.log(util)</span>\\n    <span class=\\"hljs-keyword\\">let</span> group=[[util[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">1</span>]]]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;util.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(util[i][<span class=\\"hljs-number\\">0</span>]===util[i<span class=\\"hljs-number\\">-1</span>][<span class=\\"hljs-number\\">0</span>]){\\n            group[group.length<span class=\\"hljs-number\\">-1</span>].push(util[i][<span class=\\"hljs-number\\">1</span>])\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            group.push([util[i][<span class=\\"hljs-number\\">1</span>]])\\n        }\\n    }\\n    <span class=\\"hljs-comment\\">// let group=[[0]]</span>\\n    <span class=\\"hljs-comment\\">// for(let i=1;i&lt;uf.length;i++){</span>\\n    <span class=\\"hljs-comment\\">//     let hasG=false</span>\\n    <span class=\\"hljs-comment\\">//     for(let j=0;j&lt;group.length;j++){</span>\\n    <span class=\\"hljs-comment\\">//         let g=group[j][0]</span>\\n    <span class=\\"hljs-comment\\">//         if(find(i)===find(g)){</span>\\n    <span class=\\"hljs-comment\\">//             group[j].push(i)</span>\\n    <span class=\\"hljs-comment\\">//             hasG=true</span>\\n    <span class=\\"hljs-comment\\">//             break</span>\\n    <span class=\\"hljs-comment\\">//         }</span>\\n    <span class=\\"hljs-comment\\">//     }</span>\\n    <span class=\\"hljs-comment\\">//     if(!hasG){</span>\\n    <span class=\\"hljs-comment\\">//         group.push([i])</span>\\n    <span class=\\"hljs-comment\\">//     }</span>\\n    <span class=\\"hljs-comment\\">// }</span>\\n    <span class=\\"hljs-comment\\">// console.log(uf,group)</span>\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;group.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> g=group[i]\\n        <span class=\\"hljs-keyword\\">let</span> c1={}\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;g.length;j++){\\n            <span class=\\"hljs-keyword\\">if</span>(c1[source[g[j]]]==<span class=\\"hljs-literal\\">null</span>)c1[source[g[j]]]=<span class=\\"hljs-number\\">0</span>\\n            c1[source[g[j]]]++\\n        }\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;g.length;j++){\\n            <span class=\\"hljs-keyword\\">let</span> t=target[g[j]]\\n            <span class=\\"hljs-keyword\\">if</span>(c1[t]&gt;<span class=\\"hljs-number\\">0</span>)c1[t]--\\n            <span class=\\"hljs-keyword\\">else</span> res++\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"minimize-hamming-distance-after-swap-operations","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e24\u4e2a\u6574\u6570\u6570\u7ec4 <code>source</code> \u548c <code>target</code> \uff0c\u957f\u5ea6\u90fd\u662f <code>n</code> \u3002\u8fd8\u6709\u4e00\u4e2a\u6570\u7ec4 <code>allowedSwaps</code> \uff0c\u5176\u4e2d\u6bcf\u4e2a <code>allowedSwaps[i] = [a<sub>i</sub>, b<sub>i</sub>]</code> \u8868\u793a\u4f60\u53ef\u4ee5\u4ea4\u6362\u6570\u7ec4 <code>source</code> \u4e2d\u4e0b\u6807\u4e3a <code>a<sub>i</sub></code> \u548c <code>b<sub>i</sub></code>\uff08<strong>\u4e0b\u6807\u4ece 0 \u5f00\u59cb</strong>\uff09\u7684\u4e24\u4e2a\u5143\u7d20\u3002\u6ce8\u610f\uff0c\u4f60\u53ef\u4ee5\u6309 <strong>\u4efb\u610f</strong> \u987a\u5e8f <strong>\u591a\u6b21</strong> \u4ea4\u6362\u4e00\u5bf9\u7279\u5b9a\u4e0b\u6807\u6307\u5411\u7684\u5143\u7d20\u3002</p>\\n\\n<p>\u76f8\u540c\u957f\u5ea6\u7684\u4e24\u4e2a\u6570\u7ec4\xa0<code>source</code> \u548c <code>target</code> \u95f4\u7684 <strong>\u6c49\u660e\u8ddd\u79bb</strong> \u662f\u5143\u7d20\u4e0d\u540c\u7684\u4e0b\u6807\u6570\u91cf\u3002\u5f62\u5f0f\u4e0a\uff0c\u5176\u503c\u7b49\u4e8e\u6ee1\u8db3\xa0<code>source[i] != target[i]</code> \uff08<strong>\u4e0b\u6807\u4ece 0 \u5f00\u59cb</strong>\uff09\u7684\u4e0b\u6807 <code>i</code>\uff08<code>0 &lt;= i &lt;= n-1</code>\uff09\u7684\u6570\u91cf\u3002</p>\\n\\n<p>\u5728\u5bf9\u6570\u7ec4 <code>source</code> \u6267\u884c <strong>\u4efb\u610f</strong> \u6570\u91cf\u7684\u4ea4\u6362\u64cd\u4f5c\u540e\uff0c\u8fd4\u56de <code>source</code> \u548c <code>target</code> \u95f4\u7684 <strong>\u6700\u5c0f\u6c49\u660e\u8ddd\u79bb</strong> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>source = [1,2,3,4], target = [2,1,4,5], allowedSwaps = [[0,1],[2,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>source \u53ef\u4ee5\u6309\u4e0b\u8ff0\u65b9\u5f0f\u8f6c\u6362\uff1a\\n- \u4ea4\u6362\u4e0b\u6807 0 \u548c 1 \u6307\u5411\u7684\u5143\u7d20\uff1asource = [<strong>2</strong>,<strong>1</strong>,3,4]\\n- \u4ea4\u6362\u4e0b\u6807 2 \u548c 3 \u6307\u5411\u7684\u5143\u7d20\uff1asource = [2,1,<strong>4</strong>,<strong>3</strong>]\\nsource \u548c target \u95f4\u7684\u6c49\u660e\u8ddd\u79bb\u662f 1 \uff0c\u4e8c\u8005\u6709 1 \u5904\u5143\u7d20\u4e0d\u540c\uff0c\u5728\u4e0b\u6807 3 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>source = [1,2,3,4], target = [1,3,2,4], allowedSwaps = []\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e0d\u80fd\u5bf9 source \u6267\u884c\u4ea4\u6362\u64cd\u4f5c\u3002\\nsource \u548c target \u95f4\u7684\u6c49\u660e\u8ddd\u79bb\u662f 2 \uff0c\u4e8c\u8005\u6709 2 \u5904\u5143\u7d20\u4e0d\u540c\uff0c\u5728\u4e0b\u6807 1 \u548c\u4e0b\u6807 2 \u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>source = [5,1,2,4,3], target = [1,5,4,2,3], allowedSwaps = [[0,4],[4,2],[1,3],[1,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == source.length == target.length</code></li>\\n\\t<li><code>1 &lt;= n &lt;= 10<sup>5</sup></code></li>\\n\\t<li><code>1 &lt;= source[i], target[i] &lt;= 10<sup>5</sup></code></li>\\n\\t<li><code>0 &lt;= allowedSwaps.length &lt;= 10<sup>5</sup></code></li>\\n\\t<li><code>allowedSwaps[i].length == 2</code></li>\\n\\t<li><code>0 &lt;= a<sub>i</sub>, b<sub>i</sub> &lt;= n - 1</code></li>\\n\\t<li><code>a<sub>i</sub> != b<sub>i</sub></code></li>\\n</ul>\\n","title":"1722. \u6267\u884c\u4ea4\u6362\u64cd\u4f5c\u540e\u7684\u6700\u5c0f\u6c49\u660e\u8ddd\u79bb","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22","\u5e76\u67e5\u96c6"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1722"}')}}]);